// Format error into readable notification
const err = $input.first().json;

const payload = {
  subject: `⚠️ n8n Error: ${err.workflow?.name || "Unknown"}`,
  text: `🚨 n8n Workflow Error

📋 Workflow: ${err.workflow?.name || "Unknown"}
🔧 Failed Node: ${err.node || "Unknown"}
❌ Error: ${err.error?.message || err.message || "No message"}
⏰ Time: ${err.execution?.startedAt || new Date().toISOString()}
🔗 Execution ID: ${err.execution?.id || "N/A"}

Full error payload:
${JSON.stringify(err, null, 2)}`
};
return [{ json: payload }];
